valore=(int)(ordinate[imin][sottop_selez]-(dbm-ascisse[imin][sottop_selez])*(ordinate[imin][sottop_selez]-ordinate[imagg][sottop_selez])/(ascisse[imagg][sottop_selez]-ascisse[imin][sottop_selez]));


sprintf(stringa1,"%3.0f",volts);
