void
zero_f_onoff_cbk(w, client_data, call_data)
 Widget w;
 XtPointer client_data;
 XtPointer call_data;
{
    Arg args[10];
    Boolean argok;
    char cmd[20];
    char frame_to_s[1024], frame_to_r[1024] ;
    int nb_to_s, nb_to_r ;
    int cnt;


if ( pf_onoff[sottop_selez] )

  {

    switch ( zero_f_onoff[sottop_selez] )
        {
        case SPENTO :
        zero_f_onoff[sottop_selez]=ACCESO;


        XtSetArg(args[2], XmNbackground, CONVERT(pushButton19, "red", XmRPixel, 0, &argok));
        XtSetArg(args[1], XmNforeground, CONVERT(pushButton19, "black", XmRPixel, 0, &argok));
        /*XtSetArg(args[0], XmNlabelString, XmStringCreate("soft tuning:ON", XmFONTLIST_DEFAULT_TAG));*/
        XtSetArg(args[0], XmNlabelString, CONVERT(pushButton19, ":::t\"soft tuning\"\"ON\"", XmRXmString, 0, &argok)); 

if ( sottop_tipo[sottop_selez] == 0 )
        {
        /* BUNCHER */
        XtSetValues(pushButton32, args, 3);
        }

else
        {
        /* POSTCHOPPER */
        XtSetValues(pushButton19, args, 3);
        }

if ( soft_verbose ) printf ("soft tuning:ON su %s", etichetta[sottop_selez]);


if ( auto_zero_onoff == 0 )
	{
	auto_zero_onoff = 1;
        auto_interval = XtAppAddTimeOut(XtWidgetToApplicationContext(bulletinBoard), 600, auto_zero, NULL);
	}
	
#ifdef TTTT
/* accendo anche phase feedback */


        pf_onoff[sottop_selez]=ACCESO;

        strcpy(cmd,"!PHFBK=1");

        XtSetArg(args[2], XmNbackground, CONVERT(pushButton31, "red", XmRPixel, 0, &argok));
        XtSetArg(args[1], XmNforeground, CONVERT(pushButton31, "black", XmRPixel, 0, &argok));
        /*XtSetArg(args[0], XmNlabelString, XmStringCreate("ph.feedb.:ON", XmFONTLIST_DEFAULT_TAG));*/
	XtSetArg(args[0], XmNlabelString, CONVERT(pushButton31, ":::t\"phase feedb.\"\"ON\"", XmRXmString, 0, &argok));

if ( sottop_tipo[sottop_selez] == 0 )
        {
        /* BUNCHER */
        XtSetValues(pushButton31, args, 3);
        }

else
        {
        /* POSTCHOPPER */
        XtSetValues(pushButton21, args, 3);
        }


     /* write to server */
        if (  write(rf_fildes[sottop_selez],cmd,sizeof(cmd)) < 0 )
            {
            perror( "\nclient: error writing to s streamsocket\n" ) ;
            }
        if (net_verbose) printf (" scritto %s su   %d\n", cmd, rf_fildes[sottop_selez]);

     /* listen to server */
        if ( read( rf_fildes[sottop_selez], frame_to_r, nb_to_r ) < 0 )
            {
            perror( "\nclient: error reading from s streamsocket\n" ) ;
            }
        if (net_verbose) printf (" letto %s da   %d\n", frame_to_r, rf_fildes[sottop_selez]);

if ( strncmp (frame_to_r, "Not Done", 8) == 0)
        {
        rf_is_alive[sottop_selez] = 0;
        pdr = sottop_selez;
        refresh();
        }


#endif
        break;

        case ACCESO :

        zero_f_onoff[sottop_selez]=SPENTO;

        XtSetArg(args[2], XmNbackground, CONVERT(pushButton19, "#00ff00", XmRPixel, 0, &argok));
        XtSetArg(args[1], XmNforeground, CONVERT(pushButton19, "black", XmRPixel, 0, &argok));
        /*XtSetArg(args[0], XmNlabelString, XmStringCreate("soft tuning:OFF", XmFONTLIST_DEFAULT_TAG));*/
        XtSetArg(args[0], XmNlabelString, CONVERT(pushButton19, ":::t\"soft tuning\"\"OFF\"", XmRXmString, 0, &argok)); 

if ( sottop_tipo[sottop_selez] == 0 )
        {
        /* BUNCHER */
        XtSetValues(pushButton32, args, 3);
        }

else
        {
        /* POSTCHOPPER */
        XtSetValues(pushButton19, args, 3);
        }

if ( soft_verbose ) printf ("soft tuning:OFF su %s", etichetta[sottop_selez]);


auto_zero_onoff = 0;
if ( soft_verbose )printf ( "  9999999999999999     \n\n");

for (cnt = 0 ; cnt < max_sp; cnt++)
	{
	if ( soft_verbose )printf ( "la correzione err. freq. e' %d per %s", zero_f_onoff[cnt], etichetta[cnt]);
	if ( soft_verbose )printf ( "la correzione err. amp.  e' %d per %s", zero_a_onoff[cnt], etichetta[cnt]);
	if ( zero_f_onoff[cnt] == 1 ) auto_zero_onoff = 1;
	if ( zero_a_onoff[cnt] == 1 ) auto_zero_onoff = 1;
	}

if ( soft_verbose )printf ( "  9999999999999999     \n\n");


        break;

	}


  }



}

