void
save_conf_cbk(w, client_data, call_data)
 Widget w;
 XtPointer client_data;
 XtPointer call_data;
{
    XmAnyCallbackStruct *acs=(XmAnyCallbackStruct*)call_data;

char savefile[100];
char command[100];
FILE *device_file;


strcpy(savefile, "configurazione/");
strcat(savefile, nome_file_config[sottop_selez]);
sprintf(command, "cp configurazione/%s configurazione/%s.bak", nome_file_config[sottop_selez], nome_file_config[sottop_selez]);
system(command);
if (config_verbose) printf("il file da scrivere e': %s\n", savefile);
if (config_verbose) printf("il comando e': %s\n", command);

device_file = fopen ( savefile, "w" );


/* riga relativa al nome del dispositivo */
fprintf(device_file, "%s", etichetta[sottop_selez]);

/* nome del file di calibrazione */
fprintf(device_file, "%s\n", nome_calibr[sottop_selez]);

/* costanti per il calcolo del campo rf */
fprintf(device_file, "%-.1f %-.1f %-.1f %-.1f\n", kappa[sottop_selez], min_field[sottop_selez], max_field[sottop_selez], atten_field[sottop_selez]);

/* host su cui gira il server rf e numero porta */
fprintf(device_file, "%s %d\n", rf_host[sottop_selez], rf_socket[sottop_selez] );

/* host, numero porta, numero motore tuning */
fprintf(device_file, "%s %d %d\n", za_host[sottop_selez], za_socket[sottop_selez], motor[sottop_selez] );

/* numero porta parallela, numero bit amplificatore */
fprintf(device_file, "%s %d %d %d\n", za_ampli_host[sottop_selez], za_ampli_socket[sottop_selez], za_par_io_port[sottop_selez], za_ampl_bit[sottop_selez] );

/* numero passi slow tuning numero passi fast tuning */
fprintf(device_file, "%d %d %d %f\n", tu_step_slow[sottop_selez] , tu_step_fast[sottop_selez], tu_step_fast_fast[sottop_selez], end_fr_corr[sottop_selez]);

/* soglia intervento zero amplitude error e variaz. quiesc. pow. */
fprintf(device_file, "%d %d\n", zero_a_soglia[sottop_selez], zero_a_step[sottop_selez]);

/* soglia intervento zero frequency error e num. passi inviati al motore */
fprintf(device_file, "%d %d\n", zero_f_soglia[sottop_selez], zero_f_step[sottop_selez]);

if ( sottop_tipo[sottop_selez] == 1 )
        {
        /* POSTCHOPPER */
	/* porta fase postchopper */
	fprintf(device_file, "%d\n", postchopper_ph_port[sottop_selez]);
	}

/* variabili spostamento cursori paginette piccole */
fprintf(device_file, "%d %f\n", amp_err_min[sottop_selez], max_var_field[sottop_selez]);

fclose ( device_file ) ;


}

